package org.apache.commons.csv;
import java.io.Serializable;
import java.util.Arrays;
import java.util.Iterator;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

class CSVRecordTest {

    @Test
    void testIsConsistent_mappingNull() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Prepare values array (can be empty or any)
        String[] values = new String[] {"a", "b"};

        // mapping is null
        Map<String, Integer> mapping = null;

        // Create CSVRecord instance via constructor
        CSVRecord record = new CSVRecord(values, mapping, null, 1L);

        // Use reflection to invoke isConsistent method
        Method isConsistentMethod = CSVRecord.class.getDeclaredMethod("isConsistent");
        isConsistentMethod.setAccessible(true);

        boolean result = (boolean) isConsistentMethod.invoke(record);

        assertTrue(result, "When mapping is null, isConsistent should return true");
    }

    @Test
    void testIsConsistent_mappingSizeEqualsValuesLength() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);

        CSVRecord record = new CSVRecord(values, mapping, "comment", 5L);

        Method isConsistentMethod = CSVRecord.class.getDeclaredMethod("isConsistent");
        isConsistentMethod.setAccessible(true);

        boolean result = (boolean) isConsistentMethod.invoke(record);

        assertTrue(result, "When mapping size equals values length, isConsistent should return true");
    }

    @Test
    void testIsConsistent_mappingSizeNotEqualsValuesLength() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);

        CSVRecord record = new CSVRecord(values, mapping, null, 10L);

        Method isConsistentMethod = CSVRecord.class.getDeclaredMethod("isConsistent");
        isConsistentMethod.setAccessible(true);

        boolean result = (boolean) isConsistentMethod.invoke(record);

        assertFalse(result, "When mapping size does not equal values length, isConsistent should return false");
    }
}
